mapper.select:
SELECT a.*,b.*,c.parent_path,c.merchant_level
FROM ct_in_order a
JOIN ct_in_order_detail b on a.id = b.order_id
left join ct_merchant c on c.user_id = a.merchant_id


        and b.agent_id = #{dto.agentId}


        and b.agent_name like concat('%',#{dto.agentName},'%')


        and b.shop_id = #{dto.shopId}


        and b.shop_name like concat('%',#{dto.shopName},'%')


        and a.merchant_id = #{dto.merchantId}


        and a.merchant_name like concat('%',#{dto.merchantName},'%')


        and a.channel_id = #{dto.channelId}


        and a.channel_name like concat('%',#{dto.channelName},'%')


        and a.shop_order_no like concat('%',#{dto.shopOrderNo},'%')


        and a.trade_no like concat('%',#{dto.tradeNo},'%')


        and a.order_status = #{dto.orderStatus}


        and a.callback_status = #{dto.callbackStatus}


        and a.order_time >= #{dto.startTime}


        and a.order_time <= #{dto.endTime}


        and a.member_ip = #{dto.memberIp}


        and a.nick_name like  concat('%',#{dto.recipient},'%')


        and a.account_number like  concat('%',#{dto.accountNumber},'%')


        and a.merchant_id in

            #{item}

        and a.merchant_id != #{dto.selftMerchantId}


        and c.parent_path like concat(#{dto.parentMerchantName}, '%')


order by a.id desc

SELECT sum(order_amount) as totalAmount,count(a.id) as totalCount
FROM ct_in_order a
JOIN ct_in_order_detail b on a.id = b.order_id
left join ct_merchant c on c.user_id = a.merchant_id
where a.order_status = 1

        and b.agent_id = #{dto.agentId}


        and b.agent_name like concat('%',#{dto.agentName},'%')


        and b.shop_id = #{dto.shopId}


        and b.shop_name like concat('%',#{dto.shopName},'%')


        and a.merchant_id = #{dto.merchantId}


        and a.merchant_name like concat('%',#{dto.merchantName},'%')


        and a.channel_id = #{dto.channelId}


        and a.channel_name like concat('%',#{dto.channelName},'%')


        and a.shop_order_no like concat('%',#{dto.shopOrderNo},'%')


        and a.trade_no like concat('%',#{dto.tradeNo},'%')


        and a.order_status = #{dto.orderStatus}


        and a.callback_status = #{dto.callbackStatus}


        and ifnull(a.finish_time,a.order_time) >= #{dto.startTime}


        and ifnull(a.finish_time,a.order_time) <= #{dto.endTime}


        and a.member_ip = #{dto.memberIp}


        and a.nick_name like  concat('%',#{dto.recipient},'%')


        and a.account_number like  concat('%',#{dto.accountNumber},'%')


        and a.merchant_id in

            #{item}

        and a.merchant_id != #{dto.selftMerchantId}


        and c.parent_path like concat(#{dto.parentMerchantName}, '%')

SELECT SUM(order_amount) as totalAmount,count(a.id) as totalCount, SUM(order_amount) as childAmount,
(SELECT SUM(change_amount) FROM ct_merchant_amount_records r WHERE r.agent_id = b.agent_id
AND amount_type = 2 AND change_type = 1

    AND r.create_time >= #{dto.startTime}


    AND r.create_time <= #{dto.endTime}

) as agentFee
FROM ct_in_order a
JOIN ct_in_order_detail b on a.id = b.order_id
where a.order_status = 1

    and b.agent_id = #{dto.agentId}


    and b.shop_id = #{dto.shopId}


    and a.merchant_id = #{dto.merchantId}


    and ifnull(a.finish_time,a.order_time) >= #{dto.startTime}


    and ifnull(a.finish_time,a.order_time) <= #{dto.endTime}

group by b.agent_id

SELECT SUM(order_amount) as totalAmount
FROM ct_in_order a
JOIN ct_in_order_detail b on a.id = b.order_id
where a.order_status = 1

    and ifnull(a.finish_time,a.order_time) >= #{startTime}


    and ifnull(a.finish_time,a.order_time) <= #{endTime}


    and a.merchant_id in

        #{item}

SELECT qrcode_id,SUM(order_amount) as totalAmount,count(1) as totalCount
FROM ct_in_order b
WHERE order_status = 1

and ifnull(b.finish_time,b.order_time) >= #{startTime}
and ifnull(b.finish_time,b.order_time) <= #{endTime}
  and merchant_id in

        #{item}

GROUP BY qrcode_id

select * from ( SELECT b.merchant_id,c.user_name as merchant_name,b.nick_name,b.account_number,b.`qrcode_type`,b.`qrcode_value` ,b.`qrcode_url` , b.`account_remark` ,b.uid, b.min_amount,b.max_amount,b.day_limit,b.`status`,b.create_time,b.del_flag, d.id as channel_id,d.channel_name,c.work_status,c.order_permission, case when b.`status` = 0 and b.del_flag = 0 and c.work_status = 0 and c.order_permission = 0 and c.status = 0 then 0 else 1 end as enterOrderStatus, SUM(IFNULL(a.successCount,0)) as successCount, SUM(IFNULL(a.successAmount,0)) as successAmount, SUM(IFNULL(a.totalCount,0)) as totalCount, SUM(IFNULL(a.totalAmount,0)) as totalAmount FROM ct_merchant_qrcode b join ct_merchant c on b.merchant_id = c.user_id join ct_channel d on b.channel_id = d.id LEFT JOIN (SELECT qrcode_id,channel_id,SUM(order_amount) as totalAmount,COUNT(id) as totalCount, SUM(CASE WHEN order_status = 1 then order_amount ELSE 0 END) as successAmount, SUM(CASE WHEN order_status = 1 then 1 ELSE 0 END) as successCount FROM `ct_in_order` WHERE qrcode_id is NOT NULL
and finish_time >= #{dto.startDate}
and finish_time <= #{dto.endDate}
group by qrcode_id,channel_id ) a on a.qrcode_id = b.id and d.id = a.channel_id WHERE c.del_flag = 0
and c.user_name = #{dto.merchantName}
and b.nick_name like concat('%',#{dto.nickName},'%')
and b.account_number like concat('%',#{dto.accountNumber},'%')
and b.agent_id = #{dto.agentId}
and b.channel_id = #{dto.channelId}
and b.status = #{dto.status}
and b.del_flag = #{dto.delFlag}
and c.work_status = #{dto.workStatus}
and c.order_permission = #{dto.orderPermission}
and (b.`status` != 0 or b.del_flag != 0 or c.work_status != 0 or c.order_permission != 0 or c.status != 0)
and (b.`status` = 0 and b.del_flag = 0 and c.work_status = 0 and c.order_permission = 0 and c.status = 0)
GROUP BY b.merchant_id,c.user_name,b.nick_name,b.account_number,b.`qrcode_type`,b.`qrcode_value` ,b.`qrcode_url` , b.`account_remark` ,b.uid, b.min_amount,b.max_amount,b.day_limit,b.`status`,b.create_time,b.del_flag,d.id,d.channel_name,c.work_status,c.order_permission )m order by m.successAmount desc,m.totalAmount desc

SELECT n.user_id,n.user_name,m.balance as todayBalance,
m.yes_balance,n.parent_path,
totalCount,successCount,totalMoney,successMoney,merchantFee,
ifnull((SELECT sum(change_amount) from ct_merchant_amount_records r join  ct_merchant mr on mr.user_id = r.user_id
WHERE (r.change_type = 2)
    and amount_type = 1
    and mr.parent_path like concat(n.parent_path,'%')

        and r.create_time >= #{dto.startTime}


        and r.create_time <= #{dto.endTime}

),0) as chargeMoney
FROM ct_merchant n
LEFT JOIN (SELECT SUBSTR(a.parent_path,1,locate('/',a.parent_path)-1) as merchant_id,
IFNULL(SUM( a.balance ),0) AS balance,
IFNULL(SUM( a.yes_balance ),0) AS yes_balance,
IFNULL(COUNT( b.id ),0) AS totalCount,
IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount,
IFNULL(sum( b.order_amount ),0) AS totalMoney,
IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney,
IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_one/100 ELSE 0 END ),2),0) AS merchantFee
FROM ct_merchant a
LEFT JOIN ct_in_order b on a.user_id = b.merchant_id
LEFT JOIN ct_in_order_detail c on b.id = c.order_id


        and a.agent_id = #{dto.agentId}


        and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}


        and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}


GROUP BY SUBSTR(a.parent_path,1,locate('/',a.parent_path)-1)
) m on m.merchant_id = n.user_id
where merchant_level = 1

    and n.agent_id = #{dto.agentId}


    and n.user_id = #{dto.merchantId}


    and x.user_id = #{dto.shopId}


    and n.user_name like concat('%', #{dto.merchantName},'%')


    and x.user_name like concat('%', #{dto.shopName},'%')

SELECT DATE_FORMAT(ifnull(b.finish_time,b.order_time),'%Y-%m-%d') as userName,
       count(b.id) as totalCount,
       IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount,
       IFNULL(sum( b.order_amount ),0) AS totalMoney,
       IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney
FROM ct_in_order b
join ct_in_order_detail a on b.id = a.order_id


        and a.agent_id = #{dto.agentId}


        and b.merchant_id = #{dto.merchantId}


        and a.shop_id = #{dto.shopId}


        and b.merchant_name like concat('%', #{dto.merchantName},'%')


        and a.shop_name like concat('%', #{dto.shopName},'%')


        and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}


        and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}


GROUP BY DATE_FORMAT(ifnull(b.finish_time,b.order_time),'%Y-%m-%d')

SELECT b.channel_id as userId,b.channel_name as userName,
count(b.id) as totalCount,
IFNULL(SUM( b.id ),0) AS totalCount,
IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount,
IFNULL(sum( b.order_amount ),0) AS totalMoney,
IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney
FROM ct_in_order b
join ct_in_order_detail a on b.id = a.order_id


        and a.agent_id = #{dto.agentId}


        and b.merchant_id = #{dto.merchantId}


        and a.shop_id = #{dto.shopId}


        and b.merchant_name like concat('%', #{dto.merchantName},'%')


        and a.shop_name like concat('%', #{dto.shopName},'%')


        and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}


        and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}


GROUP BY b.channel_id,b.channel_name

SELECT a.shop_id as userId,a.shop_name as userName,
count(b.id) as totalCount,
IFNULL(SUM( b.id ),0) AS totalCount,
IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount,
IFNULL(sum( b.order_amount ),0) AS totalMoney,
IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney
FROM ct_in_order b
join ct_in_order_detail a on b.id = a.order_id


        and a.agent_id = #{dto.agentId}


        and b.merchant_id = #{dto.merchantId}


        and a.shop_id = #{dto.shopId}


        and b.merchant_name like concat('%', #{dto.merchantName},'%')


        and a.shop_name like concat('%', #{dto.shopName},'%')


        and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}


        and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}


GROUP BY a.shop_id,a.shop_name

SELECT a.user_id, IFNULL(COUNT( b.id ),0) AS totalCount, IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount, IFNULL(sum( b.order_amount ),0) AS totalMoney, IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney FROM ct_merchant a JOIN ct_in_order b on a.user_id = b.merchant_id where a.parent_path like concat(#{dto.childPathStart}, '%')
and a.agent_id = #{dto.agentId}
and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}
and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}
GROUP BY a.user_id

SELECT SUBSTR(a.parent_path,1,locate('/',a.parent_path)-1) as userId,sum(balance) as todayBalance, sum(yes_balance) as yes_balance FROM ct_merchant a
and a.agent_id = #{agentId}
GROUP BY SUBSTR(a.parent_path,1,locate('/',a.parent_path)-1)

SELECT user_id,user_name,n.channelId,n.channelName,IFNULL(n.totalCount,0) totalCount, IFNULL(n.totalMoney,0) totalMoney,IFNULL(n.successCount,0) successCount,IFNULL(n.successMoney,0) successMoney FROM ct_merchant m LEFT JOIN ( SELECT SUBSTR(c.parent_path,1,locate('/',c.parent_path)-1) as merchantId,b.channel_id as channelId,b.channel_name as channelName, IFNULL(count( b.id ),0) AS totalCount, IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount, IFNULL(sum( b.order_amount ),0) AS totalMoney, IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney FROM ct_merchant c join ct_in_order b on c.user_id = b.merchant_id join ct_in_order_detail a on b.id = a.order_id
and a.agent_id = #{dto.agentId}
and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}
and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}
GROUP BY SUBSTR(c.parent_path,1,locate('/',c.parent_path)-1),b.channel_id,b.channel_name ) n on m.user_id = n.merchantId WHERE merchant_level = 1 and n.channelId is not null
and m.agent_id = #{dto.agentId}
and m.merchant_id = #{dto.merchantId}
and m.merchant_name like concat('%', #{dto.merchantName},'%')
and m.parent_path like concat(#{dto.childPathStart}, '%')
order by IFNULL(n.successMoney,0) desc

SELECT a.merchant_id,a.merchant_name,merchant_rate,channel_id,channel_name,merchant_rate_one as dianwei, merchant_rate_one,merchant_rate_two,merchant_rate_three,merchant_rate_four,merchant_rate_five,c.parent_path, count(a.id) as totalCount, SUM(order_amount) as totalAmount, ifnull(sum(commisionFeeOne),0) commissionOne,ifnull(sum(commisionFeeTwo),0) commissionTwo, ifnull(sum(commisionFeeThree),0) commissionThree,ifnull(sum(commisionFeeFour),0) commissionFour, ifnull(sum(commisionFeeFive),0) commissionFive, round((merchant_rate_one - merchant_rate_two ), 2 ) AS commissionOneRate, round(( merchant_rate_two - merchant_rate_three ), 2 ) AS commissionTwoRate, round(( merchant_rate_three - merchant_rate_four ), 2 ) AS commissionThreeRate, round(( merchant_rate_four - merchant_rate_five ), 2 ) AS commissionFourRate, ifnull(case WHEN c.merchant_level = 1 THEN sum(commisionFeeOne) WHEN c.merchant_level = 2 THEN sum(commisionFeeTwo) WHEN c.merchant_level = 3 THEN sum(commisionFeeThree) WHEN c.merchant_level = 4 THEN sum(commisionFeeFour) WHEN c.merchant_level = 5 THEN sum(commisionFeeFive) ELSE 0 END,0) AS myCommission FROM ct_in_order a JOIN ct_in_order_detail b on a.id = b.order_id JOIN ct_merchant c on a.merchant_id = c.user_id LEFT JOIN (SELECT order_no ,sum(commisionFeeOne)commisionFeeOne,sum(commisionFeeTwo)commisionFeeTwo, sum(commisionFeeThree)commisionFeeThree,sum(commisionFeeFour)commisionFeeFour,sum(commisionFeeFive)commisionFeeFive FROM(SELECT r.order_no, case when p.merchant_level = 1 then r.change_amount else 0 END as commisionFeeOne, case when p.merchant_level = 2 then r.change_amount else 0 END as commisionFeeTwo, case when p.merchant_level = 3 then r.change_amount else 0 END as commisionFeeThree, case when p.merchant_level = 4 then r.change_amount else 0 END as commisionFeeFour, case when p.merchant_level = 5 then r.change_amount else 0 END as commisionFeeFive FROM ct_merchant_amount_records r JOIN ct_merchant p on r.user_id = p.user_id WHERE r.amount_type = 2 AND r.change_type = 1
AND r.agent_id = #{dto.agentId}
AND r.create_time >= #{dto.startTime}
AND r.create_time <= #{dto.endTime}
)com GROUP BY order_no )ss on a.trade_no = ss.order_no WHERE a.order_status = 1
and b.agent_id = #{dto.agentId}
and ifnull(a.finish_time,a.order_time) >= #{dto.startTime}
and ifnull(a.finish_time,a.order_time) <= #{dto.endTime}
and a.merchant_id = #{dto.merchantId}
and a.merchant_name like concat('%', #{dto.merchantName},'%')
and c.parent_path like concat(#{dto.childPathStart}, '%')
and a.merchant_id != #{dto.neMerchantId}
and a.channel_id = #{dto.channelId}
GROUP BY a.merchant_id,a.merchant_name,c.parent_path,c.merchant_level,merchant_rate,channel_id,channel_name,merchant_rate_one,merchant_rate_two,merchant_rate_three,merchant_rate_four,merchant_rate_five

SELECT n.user_id,n.user_name,x.user_id as shop_id,x.user_name as shop_name,m.balance as todayBalance, m.yes_balance,n.parent_path, totalCount,successCount,totalMoney,successMoney,merchantFee, ifnull((SELECT sum(change_amount) from ct_merchant_amount_records r join ct_merchant mr on mr.user_id = r.user_id WHERE (r.change_type = 2 or r.change_type = 3) and amount_type = 1 and notes not like '%佣金转移%' and mr.user_id = n.user_id
and r.create_time >= #{dto.startTime}
and r.create_time <= #{dto.endTime}
),0) as chargeMoney FROM ct_merchant n JOIN ct_shop_merchant_relation k on k.merchant_id = n.user_id JOIN ct_shop x on x.user_id = k.shop_id LEFT JOIN (SELECT a.user_id as merchant_id, IFNULL(SUM( a.balance ),0) AS balance, IFNULL(SUM( a.yes_balance ),0) AS yes_balance, IFNULL(COUNT( b.id ),0) AS totalCount, IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount, IFNULL(sum( b.order_amount ),0) AS totalMoney, IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney, IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_one/100 ELSE 0 END ),2),0) AS merchantFee FROM ct_merchant a LEFT JOIN ct_in_order b on a.user_id = b.merchant_id LEFT JOIN ct_in_order_detail c on b.id = c.order_id
and a.agent_id = #{dto.agentId}
and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}
and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}
GROUP BY a.user_id ) m on m.merchant_id = n.user_id where parent_path like '10062/%'
and n.agent_id = #{dto.agentId}
and n.user_id = #{dto.merchantId}
and x.user_id = #{dto.shopId}
and n.user_name like concat('%', #{dto.merchantName},'%')
and x.user_name like concat('%', #{dto.shopName},'%')

SELECT m.user_id,m.user_name,m.parent_id,m.parent_path,m.merchant_level,ifnull(chargeMoney,0)as chargeMoney, m.balance as todayBalance,m.yes_balance, IFNULL(n.totalCount,0) as totalCount,IFNULL(n.successCount,0) as successCount,IFNULL(n.totalMoney,0) as totalMoney,IFNULL(n.successMoney,0) as successMoney, ifnull((case when #{dto.merchantLevel} = 1 then merchantFeeOne when #{dto.merchantLevel} = 2 then merchantFeeTwo when #{dto.merchantLevel} = 3 then merchantFeeThree when #{dto.merchantLevel} = 4 then merchantFeeFour when #{dto.merchantLevel} = 5 then merchantFeeFive END),0) as merchantFee FROM ct_merchant m LEFT JOIN(SELECT a.user_id, ifnull(r.chargeMoney,0) as chargeMoney , IFNULL(count( b.id ),0) AS totalCount, IFNULL(sum( CASE WHEN b.order_status = 1 THEN 1 ELSE 0 END ),0) AS successCount, IFNULL(sum( b.order_amount ),0) AS totalMoney, IFNULL(sum( CASE WHEN b.order_status = 1 THEN b.order_amount ELSE 0 END ),0) AS successMoney, IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_one/100 ELSE 0 END ),2),0) AS merchantFeeOne, IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_two/100 ELSE 0 END ),2),0) AS merchantFeeTwo, IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_three/100 ELSE 0 END ),2),0) AS merchantFeeThree, IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_four/100 ELSE 0 END ),2),0) AS merchantFeeFour, IFNULL(Round(sum( CASE WHEN b.order_status = 1 THEN b.order_amount * c.merchant_rate_five/100 ELSE 0 END ),2),0) AS merchantFeeFive FROM ct_merchant a LEFT JOIN ct_in_order b on a.user_id = b.merchant_id LEFT JOIN ct_in_order_detail c on b.id = c.order_id LEFT JOIN ( SELECT user_id,sum(change_amount) as chargeMoney from ct_merchant_amount_records r WHERE r.change_type = 3
and create_time >= #{dto.startTime}
and create_time <= #{dto.endTime}
GROUP BY user_id ) r on r.user_id = a.user_id
and a.agent_id = #{dto.agentId}
and ifnull(b.finish_time,b.order_time) >= #{dto.startTime}
and ifnull(b.finish_time,b.order_time) <= #{dto.endTime}
GROUP BY a.user_id )n on m.user_id = n.user_id where m.parent_path like concat(#{dto.childPathStart},'%')
and m.user_id = #{dto.merchantId}
and m.user_name like concat('%', #{dto.merchantName},'%')

SELECT a.*,b.*,c.parent_path,c.merchant_level
FROM ct_in_order a
JOIN ct_in_order_detail b on a.id = b.order_id
left join ct_merchant c on c.user_id = a.merchant_id


        and b.agent_id = #{dto.agentId}


        and b.agent_name like concat('%',#{dto.agentName},'%')


        and b.shop_id = #{dto.shopId}


        and b.shop_name like concat('%',#{dto.shopName},'%')


        and a.merchant_id = #{dto.merchantId}


        and a.merchant_name like concat('%',#{dto.merchantName},'%')


        and a.channel_id = #{dto.channelId}


        and a.channel_name like concat('%',#{dto.channelName},'%')


        and a.shop_order_no like concat('%',#{dto.shopOrderNo},'%')


        and a.trade_no like concat('%',#{dto.tradeNo},'%')


        and a.order_status = #{dto.orderStatus}


        and a.callback_status = #{dto.callbackStatus}


        and a.order_time >= #{dto.startTime}


        and a.order_time <= #{dto.endTime}


        and a.merchant_id in

            #{item}

        and a.merchant_id != #{dto.selftMerchantId}


        and c.parent_path like concat(#{dto.parentMerchantName}, '%')


order by a.id desc

SELECT ROUND((sum(balance) + SUM(freeze_amount)),2) as balance
FROM ct_merchant
WHERE agent_id = #{agentId}
